INSERT INTO library (lang, lb_id, difficulty, page, title, tags, summary, content, eg_in, eg_out) VALUES
('python', 91, 'intermediate', 1, '捕获特定异常类型', '["异常处理","特定异常"]', '使用 except 后接具体的异常类名，只捕获该类型的异常。', '在 try 块后，可以使用多个 except 子句来分别处理不同类型的异常。通过指定具体的异常类（如 ValueError, TypeError），可以针对性地处理特定错误，避免使用过于宽泛的 except Exception。这有助于更精确地定位问题，并允许其他未预见的异常向上传播，便于调试。', '["try:\n    num = int(input(\"请输入一个整数: \"))\n    result = 10 / num\n    print(f\"结果是: {result}\")\nexcept ValueError:\n    print(\"输入错误，无法转换为整数！\")\nexcept ZeroDivisionError:\n    print(\"错误，除数不能为零！\")"]', '["请输入一个整数: abc\n输入错误，无法转换为整数！"]'),
('python', 92, 'intermediate', 1, '捕获多个异常', '["异常处理","多个异常"]', '在一个 except 子句中通过元组捕获多种类型的异常。', '如果对于几种不同的异常类型，希望采取相同的处理逻辑，可以将这些异常类型放入一个元组中，放在一个 except 关键字之后。这样可以使代码更简洁，避免重复的 except 块。', '["try:\n    with open(\"data.txt\", \"r\") as f:\n        content = f.read()\n        num = int(content.strip())\nexcept (FileNotFoundError, ValueError) as e:\n    print(f\"操作失败，原因: {type(e).__name__}: {e}\")"]', '["操作失败，原因: FileNotFoundError: [Errno 2] No such file or directory: \\'data.txt\\'"]'),
('python', 93, 'intermediate', 1, '获取异常对象信息', '["异常处理","异常对象","as关键字"]', '使用 as 关键字将捕获的异常赋值给一个变量，以便访问其详细信息。', '在 except 子句中使用 `as` 关键字可以将捕获的异常对象绑定到一个变量（通常命名为 `e`）。通过这个异常对象，可以访问其 `args` 属性（错误参数元组）或直接打印/记录它来获取错误描述，有助于记录日志或进行更复杂的错误处理。', '["try:\n    x = 1 / 0\nexcept ZeroDivisionError as e:\n    print(f\"异常类型: {type(e).__name__}\")\n    print(f\"异常信息: {e}\")\n    print(f\"异常参数: {e.args}\")"]', '["异常类型: ZeroDivisionError\n异常信息: division by zero\n异常参数: (\\'division by zero\\',)"]'),
('python', 94, 'intermediate', 1, 'try-except-else 结构', '["异常处理","else子句"]', '当 try 块中没有发生异常时，执行 else 块中的代码。', '`else` 子句必须位于所有 `except` 子句之后。当 `try` 块中的代码正常执行，未引发任何异常时，程序会跳转到 `else` 块继续执行。这有助于清晰地分离可能引发异常的代码和仅在无异常时才应执行的代码，使逻辑更清晰。如果 try 块中发生异常并被捕获，则 else 块不会执行。', '["try:\n    num = int(input(\"输入数字: \"))\nexcept ValueError:\n    print(\"无效输入\")\nelse:\n    # 仅当转换成功时执行\n    print(f\"你输入的数字是: {num}\")\n    print(f\"它的平方是: {num ** 2}\")"]', '["输入数字: 42\n你输入的数字是: 42\n它的平方是: 1764"]'),
('python', 95, 'intermediate', 1, 'try-except-finally 结构', '["异常处理","finally子句","资源清理"]', 'finally 子句无论是否发生异常都会执行，常用于资源清理。', '`finally` 子句用于定义无论 try 块中是否发生异常，最终都必须执行的代码。它通常用于释放外部资源（如关闭文件、网络连接、数据库连接等），确保资源在任何情况下都能被正确清理。即使 try 或 except 块中使用了 return、break 或 continue，finally 块也会在离开 try...except 结构前执行。', '["def divide(a, b):\n    try:\n        result = a / b\n        print(f\"结果为: {result}\")\n        return result\nexcept ZeroDivisionError:\n        print(\"除数不能为零\")\n        return None\n    finally:\n        print(\"这是 finally 块，始终执行。\")\n\nprint(divide(10, 2))\nprint(\"---\")\nprint(divide(10, 0))"]', '["结果为: 5.0\n这是 finally 块，始终执行。\n5.0\n---\n除数不能为零\n这是 finally 块，始终执行。\nNone"]'),
('python', 96, 'intermediate', 1, '自定义异常类', '["异常处理","自定义异常","继承"]', '通过继承 Exception 或它的子类来创建用户自定义的异常。', '当内置异常类型不足以清晰地描述特定业务逻辑错误时，可以创建自定义异常类。自定义异常类通常继承自 `Exception` 基类，可以添加额外的属性（如错误码、详细信息）和方法，使错误信息更丰富、更具可读性，并能更精确地被上层代码捕获和处理。', '["class InsufficientFundsError(Exception):\n    \"\"\"账户余额不足异常\"\"\"\n    def __init__(self, balance, amount):\n        self.balance = balance\n        self.amount = amount\n        message = f\"余额不足。当前余额: {balance}, 试图提取: {amount}\"\n        super().__init__(message)\n\ndef withdraw(balance, amount):\n    if amount > balance:\n        raise InsufficientFundsError(balance, amount)\n    return balance - amount\n\ntry:\n    new_balance = withdraw(100, 150)\nexcept InsufficientFundsError as e:\n    print(f\"取款失败: {e}\")\n    print(f\"详细信息: 余额{e.balance}, 需求{e.amount}\")"]', '["取款失败: 余额不足。当前余额: 100, 试图提取: 150\n详细信息: 余额100, 需求150"]'),
('python', 97, 'intermediate', 1, '使用 raise 重新抛出异常', '["异常处理","raise","重新抛出"]', '在 except 块中使用不带参数的 raise 语句可以重新抛出当前正在处理的异常。', '有时在捕获异常后，可能需要进行一些日志记录或清理操作，但又不希望完全处理掉这个异常，而是希望它继续向调用栈的上层传播。此时，可以在 except 块中使用单独的 `raise` 语句（不指定异常对象）。这会重新抛出当前正在处理的同一个异常对象，保留原始的异常回溯信息。', '["def process_file(filename):\n    try:\n        with open(filename, \\'r\\') as f:\n            return f.read()\n    except FileNotFoundError:\n        print(f\"[日志] 文件 {filename} 未找到，记录此事件。\")\n        # 记录后，仍然希望上层知道这个错误\n        raise\n\ntry:\n    content = process_file(\"missing.txt\")\nexcept FileNotFoundError as e:\n    print(f\"上层捕获到: {e}\")"]', '["[日志] 文件 missing.txt 未找到，记录此事件。\n上层捕获到: [Errno 2] No such file or directory: \\'missing.txt\\'"]'),
('python', 98, 'intermediate', 1, '异常链与 from 关键字', '["异常处理","异常链","from关键字"]', '使用 raise...from 将一个新异常与导致它的原始异常链接起来。', '在捕获一个异常后引发另一个异常时，可以使用 `raise NewException(...) from original_exception` 语法。这会创建一个明确的因果关系链，将新的异常（NewException）与原始的异常（original_exception）链接起来。当新异常被捕获时，可以通过其 `__cause__` 属性访问原始异常。这有助于在复杂的调用链中追踪错误的根本原因。', '["def connect_to_database():\n    try:\n        # 模拟一个底层网络错误\n        raise ConnectionError(\"网络连接失败\")\n    except ConnectionError as e:\n        # 包裹成一个更上层的应用错误\n        raise RuntimeError(\"无法初始化数据库连接\") from e\n\ntry:\n    connect_to_database()\nexcept RuntimeError as e:\n    print(f\"捕获到运行时错误: {e}\")\n    print(f\"根本原因: {e.__cause__}\")"]', '["捕获到运行时错误: 无法初始化数据库连接\n根本原因: 网络连接失败"]'),
('python', 99, 'intermediate', 1, '断言语句 assert', '["异常处理","断言","调试"]', 'assert 语句用于在程序内部检查某个条件，如果为 False 则引发 AssertionError。', '`assert` 语句是一个调试辅助工具，用于声明某个条件在代码的某个点上应该为真。如果其后的表达式求值为 False，则会引发 `AssertionError` 异常。它通常用于检查程序逻辑的不变量、函数参数的前提条件或重要中间结果的正确性。在 Python 中，可以通过 `-O` (优化) 命令行选项来禁用所有 assert 语句。', '["def calculate_average(numbers):\n    # 前提条件：输入必须是非空列表\n    assert isinstance(numbers, list) and len(numbers) > 0, \\\"输入必须是非空列表\\\"\n    total = sum(numbers)\n    count = len(numbers)\n    # 内部逻辑检查：总数应该是数字的和\n    assert total == sum(numbers), \\\"总和计算错误\\\"  # 这个assert是多余的，仅作示例\n    return total / count\n\nprint(calculate_average([1, 2, 3, 4, 5]))\n# print(calculate_average([])) # 会触发 AssertionError: 输入必须是非空列表"]', '["3.0"]'),
('python', 100, 'intermediate', 1, '上下文管理器中的异常处理', '["异常处理","上下文管理器","with语句"]', '在 with 语句管理的代码块中，上下文管理器可以处理其内部发生的异常。', '实现上下文管理器协议（即定义了 `__enter__` 和 `__exit__` 方法的对象）的类可以控制如何处理在 with 代码块中发生的异常。`__exit__` 方法会接收异常类型、异常实例和回溯信息。如果 `__exit__` 方法返回 True，则表示它已经处理了该异常，异常不会继续传播；如果返回 False 或 None，则异常会继续向上抛出。这为资源的获取和释放提供了强大的异常安全保证。', '["class SafeResource:\n    def __enter__(self):\n        print(\"获取资源\")\n        return self\n    def __exit__(self, exc_type, exc_val, exc_tb):\n        print(\"释放资源\")\n        if exc_type is not None:\n            print(f\"在上下文管理器内发生了异常: {exc_type.__name__}: {exc_val}\")\n        # 返回 False，让异常继续传播\n        return False\n\nwith SafeResource() as res:\n    print(\"正在使用资源\")\n    # 模拟一个错误\n    raise ValueError(\"一个测试错误\")\nprint(\"这行不会被执行\")"]', '["获取资源\n正在使用资源\n释放资源\n在上下文管理器内发生了异常: ValueError: 一个测试错误\nTraceback (most recent call last):\n  ...\nValueError: 一个测试错误"]'),
('python', 101, 'intermediate', 1, '异常处理中的资源清理模式', '["异常处理","资源清理","最佳实践"]', '确保在异常发生时，已分配的资源（如文件、锁）能够被正确释放。', '即使有异常发生，也必须保证资源（如打开的文件、网络套接字、线程锁等）被正确关闭或释放。这通常通过 `try...finally` 结构或 `with` 语句（上下文管理器）来实现。`with` 语句是更推荐的方式，因为它能自动管理资源的生命周期，代码更简洁且不易出错。对于不支持上下文管理器的资源，则必须显式使用 `try...finally`。', '["# 使用 with 语句自动管理文件（推荐）\nwith open(\"output.txt\", \"w\") as f:\n    f.write(\"一些数据\")\n    # 即使这里发生异常，文件也会被正确关闭\n\n# 使用 try...finally 显式管理（当没有上下文管理器时）\nlock = threading.Lock()\nlock.acquire()\ntry:\n    # 临界区代码\n    print(\"处理共享数据\")\nfinally:\n    lock.release()  # 确保锁总是被释放"]', '["处理共享数据"]'),
('python', 102, 'intermediate', 1, '异常处理的最佳实践', '["异常处理","最佳实践","可读性"]', '遵循一些通用原则来编写健壮且清晰的异常处理代码。', '1. 只捕获你知道如何处理的异常，避免使用空的 except 或过于宽泛的 except Exception。\n2. 在靠近错误发生的地方处理异常，如果无法处理，就让它传播到合适的地方。\n3. 使用具体的异常类型，而不是通用的 Exception。\n4. 记录异常信息（使用 logging 模块），尤其是在捕获后重新抛出或吞没异常时。\n5. 保持 try 块的精简，只包含可能引发异常的代码。\n6. 优先使用上下文管理器（with）和 finally 来进行资源清理。\n7. 自定义异常应提供有意义的错误信息。', '["import logging\nlogging.basicConfig(level=logging.INFO)\n\ndef load_config(path):\n    \"\"\"加载配置文件，文件不存在时返回默认配置。\"\"\"\n    default_config = {\"key\": \"value\"}\n    try:\n        with open(path, \\'r\\') as f:\n            # 模拟解析，这里假设直接返回内容\n            return f.read()\n    except FileNotFoundError:\n        logging.info(f\"配置文件 {path} 未找到，使用默认配置。\")\n        return default_config\n    except (PermissionError, IsADirectoryError) as e:\n        logging.warning(f\"无法访问配置文件 {path}: {e}\")\n        return default_config\n    # 不捕获其他未预期的错误，让调用者知道\n\nconfig = load_config(\"config.json\")\nprint(config)"]', '["INFO:root:配置文件 config.json 未找到，使用默认配置。\n{\\'key\\': \\'value\\'}"]'),
('python', 103, 'intermediate', 1, '异常与函数返回值', '["异常处理","函数设计","错误处理"]', '在设计函数时，权衡使用异常还是返回特殊值（如None）来表示错误状态。', '通常，对于“预期可能发生的”错误（如用户输入无效、文件未找到），可以使用返回值（如 None, False, 错误码）或返回一个包含结果和错误状态的对象（如元组）。对于“程序逻辑错误”或“罕见、意外”的情况（如内存耗尽、不满足前置条件），则更适合使用异常。异常的优势在于它们会自动向上传播，不会污染正常的返回值，并且能携带丰富的错误信息。选择哪种方式取决于错误的性质和在调用链中的处理方式。', '["# 方式1：使用返回值表示“预期”错误\ndef find_user_by_id(user_id, user_list):\n    for user in user_list:\n        if user[\"id\"] == user_id:\n            return user\n    return None  # 表示未找到，这是预期情况之一\n\n# 方式2：使用异常表示“意外”或“严重”错误\ndef parse_positive_number(s):\n    \"\"\"解析字符串为正数，如果格式错误或不是正数则抛出异常。\"\"\"\n    num = float(s)\n    if num <= 0:\n        raise ValueError(f\"输入的数字 {num} 不是正数\")\n    return num\n\nusers = [{\"id\": 1, \"name\": \"Alice\"}, {\"id\": 2, \"name\": \"Bob\"}]\nprint(find_user_by_id(3, users))\ntry:\n    print(parse_positive_number(\"-5\"))\nexcept ValueError as e:\n    print(f\"解析失败: {e}\")"]', '["None\n解析失败: 输入的数字 -5.0 不是正数"]'),
('python', 104, 'intermediate', 1, '异常处理中的日志记录', '["异常处理","日志记录","logging模块"]', '在捕获异常时，使用 logging 模块记录异常信息，而不是仅仅打印。', '在生产代码中，使用 `print` 记录错误信息是不合适的，因为它缺乏灵活性（如日志级别、输出目标、格式）。`logging` 模块提供了强大的日志功能。在 except 块中，应该根据异常严重程度，使用 `logging.error()`, `logging.warning()`, `logging.info()` 等方法，并利用 `exc_info=True` 参数或 `exception()` 方法来自动记录完整的异常回溯信息。这有助于后期的问题诊断和监控。', '["import logging\nimport traceback\n\nlogging.basicConfig(level=logging.DEBUG, format=\\'%(asctime)s - %(levelname)s - %(message)s\\')\n\ndef risky_operation():\n    return 1 / 0\n\ntry:\n    risky_operation()\nexcept ZeroDivisionError:\n    # 方法1：使用 logging.exception，自动记录错误级别和完整回溯\n    logging.exception(\"执行risky_operation时发生严重错误\")\n    # 方法2：使用 logging.error 并指定 exc_info\n    # logging.error(\"执行risky_operation时发生严重错误\", exc_info=True)\n    print(\"程序已记录错误并尝试恢复...\")"]', '["2023-10-27 10:00:00,000 - ERROR - 执行risky_operation时发生严重错误\nTraceback (most recent call last):\n  File \\'<stdin>\\', line 2, in <module>\n  File \\'<stdin>\\', line 2, in risky_operation\nZeroDivisionError: division by zero\n程序已记录错误并尝试恢复..."]'),
('python', 105, 'intermediate', 1, '异常处理对性能的影响', '["异常处理","性能","最佳实践"]', '理解异常处理的成本，避免在正常流程中使用异常进行控制流。', '与正常的代码执行路径相比，触发和处理异常是一个相对昂贵的操作，因为它涉及构建异常对象、展开调用栈等。因此，**不应将异常机制用于常规的控制流程**（例如，用异常来跳出循环或进行条件分支）。异常应保留给真正的“异常”情况。对于可以通过简单条件检查来避免的错误（如检查除数是否为零），使用条件判断通常比捕获异常更高效、更清晰。', '["import time\n\ndef divide_with_check(a, b):\n    \"\"\"使用条件检查（推荐）\"\"\"\n    if b == 0:\n        return None\n    return a / b\n\ndef divide_with_exception(a, b):\n    \"\"\"依赖异常捕获\"\"\"\n    try:\n        return a / b\n    except ZeroDivisionError:\n        return None\n\n# 性能对比（在非错误路径上）\nstart = time.perf_counter()\nfor i in range(1, 1000000):\n    divide_with_check(10, i)\nelapsed_check = time.perf_counter() - start\n\nstart = time.perf_counter()\nfor i in range(1, 1000000):\n    divide_with_exception(10, i)\nelapsed_exception = time.perf_counter() - start\n\nprint(f\"条件检查耗时: {elapsed_check:.3f}秒\")\nprint(f\"异常处理耗时: {elapsed_exception:.3f}秒\")\nprint(f\"异常方式慢了: {((elapsed_exception/elapsed_check)-1)*100:.1f}%\")"]', '["条件检查耗时: 0.080秒\n异常处理耗时: 0.180秒\n异常方式慢了: 125.0%"]');